import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface PlayerHighlight {
  playerName: string;
  position: string;
  points: number;
  recentPerformance: number[];
}

interface LeagueData {
  league: {
    name: string;
    teamRank: number;
    totalPoints: number;
  };
  playerHighlights: PlayerHighlight[];
}

export default function Widget() {
  const data = response.data as LeagueData;
  const { league, playerHighlights } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1A202C' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#A0AEC0' }}>
              {league.name}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#E2E8F0' }}>
              Rank: {league.teamRank}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total Points: {league.totalPoints}
            </Typography>
          </Box>

          {playerHighlights.slice(0, 3).map((player) => (
            <Box key={player.playerName}>
              <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mb: 1 }}>
                <Box>
                  <Typography variant="body2" sx={{ color: '#F7FAFC', fontWeight: 600 }}>
                    {player.playerName}
                  </Typography>
                  <Typography variant="caption" sx={{ color: '#A0AEC0' }}>
                    {player.position}
                  </Typography>
                </Box>
                <Typography variant="body2" sx={{ color: '#E2E8F0', fontWeight: 500 }}>
                  {player.points} pts
                </Typography>
              </Stack>
              <Box sx={{ width: '100%', height: 60 }}>
                <ResponsiveChartContainer
                  series={[
                    {
                      type: 'line',
                      data: player.recentPerformance,
                      color: '#3182CE',
                      curve: 'linear',
                    },
                  ]}
                  xAxis={[
                    {
                      data: player.recentPerformance.map((_, i) => i),
                      hide: true,
                    },
                  ]}
                  yAxis={[{ hide: true }]}
                >
                  <g clipPath={`url(#${clipPathId})`}>
                    <LinePlot />
                  </g>
                  <ChartsClipPath id={clipPathId} />
                </ResponsiveChartContainer>
              </Box>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
